import { Component } from '@angular/core';
import { Course } from '../../models/course';
import { Category } from '../../models/category';
import { FormsModule } from '@angular/forms';
import { NgClass, NgStyle } from '@angular/common';
import { DiscountPipe } from '../../pips/discount'
import { DisableAfterClickDirective } from '../../directives/direct1';

@Component({
  selector: 'app-courses',
  standalone: true,
  imports: [FormsModule, NgClass, NgStyle, DiscountPipe, DisableAfterClickDirective],
  templateUrl: './courses.html',
  styleUrls: ['./courses.css']
})
export class Courses {
  selectedCatId: number = 0;

  courses: Course[] = [
    { id: 1, title: 'Angular Development', instructor: 'Mohammed', price: 1200, seats: 10, image: 'data:image/jpeg;base64,', catId: 1 },
    { id: 2, title: 'UI/UX Design', instructor: 'Sara', price: 800, seats: 0, image: 'data:image/jpeg;base64,', catId: 2 },
    { id: 3, title: 'React Mastery', instructor: 'Ahmed', price: 1100, seats: 1, image: 'data:image/jpeg;base64,', catId: 1 },
    { id: 4, title: 'Business Management', instructor: 'Ali', price: 500, seats: 25, image: 'data:image/jpeg;base64,', catId: 3 },
    { id: 5, title: 'Digital Marketing', instructor: 'Mona', price: 300, seats: 2, image: 'data:image/jpeg;base64,', catId: 4 }
  ];

  categories: Category[] = [
    { id: 1, name: "Programming" },
    { id: 2, name: "Design" },
    { id: 3, name: "Business" },
    { id: 4, name: "Marketing" }
  ];

  register(course: Course) {
    if (course.seats > 0) {
      course.seats -= 1; 
    }
  }

  getFilteredCourses(): Course[] {
    if (this.selectedCatId == 0) {
      return this.courses;
    }
    return this.courses.filter(c => c.catId == this.selectedCatId);
  }
}